query:
SELECT COUNT(*) as clients FROM clients WHERE businessOwnerId = 1650001;
SELECT COUNT(*) as appointments FROM appointments WHERE businessOwnerId = 1650001;
SELECT SUM(totalPrice) as total_revenue FROM appointments WHERE businessOwnerId = 1650001 AND status = 'completed';
SELECT COUNT(*) as this_week FROM appointments WHERE businessOwnerId = 1650001 AND date >= DATE_SUB(CURDATE(), INTERVAL 7 DAY);

